app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# OIDC Configuration
OIDC_ISSUER = os.environ.get('OIDC_ISSUER', 'https://your-oidc-provider.com')
OIDC_CLIENT_ID = os.environ.get('OIDC_CLIENT_ID', 'your-client-id')
